using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create profile 1
    Ptr sketchesObj = rootComp->sketches();
    if (!sketchesObj)
        return false;

    Ptr sketch0 = sketchesObj->add(rootComp->xZConstructionPlane());
    if (!sketch0)
        return false;

    Ptr sketchCurvesObj0 = sketch0->sketchCurves();
    if (!sketchCurvesObj0)
        return false;

    Ptr sketchCirclesObj0 = sketchCurvesObj0->sketchCircles();
    if (!sketchCirclesObj0)
        return false;

    Ptr centerPoint = adsk::core::Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    sketchCirclesObj0->addByCenterRadius(centerPoint, 5.0);

    Ptr profilesObj0 = sketch0->profiles();
    if (!profilesObj0)
        return false;

    Ptr profile0 = profilesObj0->item(0);
    if (!profile0)
        return false;

    // Create profile 2
    Ptr ctorPlanes = rootComp->constructionPlanes();
    if (!ctorPlanes)
        return false;

    Ptr ctorPlaneInput1 = ctorPlanes->createInput();
    if (!ctorPlaneInput1)
        return false;

    Ptr offset = adsk::core::ValueInput::createByString("10 cm");
    if (!offset)
        return false;

    bool ret = ctorPlaneInput1->setByOffset(rootComp->xZConstructionPlane(), offset);
    if (!ret)
        return false;

    Ptr ctorPlane1 = ctorPlanes->add(ctorPlaneInput1);
    if (!ctorPlane1)
        return false;

    Ptr sketch1 = sketchesObj->add(ctorPlane1);
    if (!sketch1)
        return false;

    Ptr sketchCurvesObj1 = sketch1->sketchCurves();
    if (!sketchCurvesObj1)
        return false;

    Ptr sketchCirclesObj1 = sketchCurvesObj1->sketchCircles();
    if (!sketchCirclesObj1)
        return false;
    sketchCirclesObj1->addByCenterRadius(centerPoint, 2.0);

    Ptr profilesObj1 = sketch1->profiles();
    if (!profilesObj1)
        return false;

    Ptr profile1 = profilesObj1->item(0);
    if (!profile1)
        return false;

    // Create profile 3
    Ptr ctorPlaneInput2 = ctorPlanes->createInput();
    if (!ctorPlaneInput2)
        return false;

    ret = ctorPlaneInput2->setByOffset(ctorPlane1, offset);
    if (!ret)
        return false;

    Ptr ctorPlane2 = ctorPlanes->add(ctorPlaneInput2);
    if (!ctorPlane2)
        return false;

    Ptr sketch2 = sketchesObj->add(ctorPlane2);
    if (!sketch2)
        return false;

    Ptr sketchCurvesObj2 = sketch2->sketchCurves();
    if (!sketchCurvesObj2)
        return false;

    Ptr sketchCirclesObj2 = sketchCurvesObj2->sketchCircles();
    if (!sketchCirclesObj2)
        return false;
    sketchCirclesObj2->addByCenterRadius(centerPoint, 10.0);

    Ptr profilesObj2 = sketch2->profiles();
    if (!profilesObj2)
        return false;

    Ptr profile2 = profilesObj2->item(0);
    if (!profile2)
        return false;

    // Create loft feature input
    Ptr feats = rootComp->features();
    if (!feats)
        return false;

    Ptr loftFeats = feats->loftFeatures();
    if (!loftFeats)
        return false;

    Ptr loftInput = loftFeats->createInput(adsk::fusion::FeatureOperations::NewBodyFeatureOperation);
    if (!loftInput)
        return false;

    Ptr loftSectionsObj = loftInput->loftSections();
    if (!loftSectionsObj)
        return false;

    Ptr loftSection0 = loftSectionsObj->add(profile0);
    if (!loftSection0)
        return false;

    Ptr loftSection1 = loftSectionsObj->add(profile1);
    if (!loftSection1)
        return false;

    Ptr loftSection2 = loftSectionsObj->add(profile2);
    if (!loftSection2)
        return false;

    // Set solid, closed, tangent edges merged and alignment options
    loftInput->isSolid(false);
    loftInput->isClosed(false);
    loftInput->isTangentEdgesMerged(true);
    loftInput->startLoftEdgeAlignment(adsk::fusion::LoftEdgeAlignments::FreeEdgesLoftEdgeAlignment);
    loftInput->endLoftEdgeAlignment(adsk::fusion::LoftEdgeAlignments::FreeEdgesLoftEdgeAlignment);

    // Create loft feature
    Ptr loftFeature = loftFeats->add(loftInput);
    if (!loftFeature)
        return false;


    return true;
}
